"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["3734"],{37611(e,n,t){t.r(n),t.d(n,{default:()=>s});var i=t(74848),r=t(47643),a=JSON.parse('{"id":259,"de":{"title":"Journal-Abgleich","prompt":"I want you to act as a scientific manuscript matcher. I will provide you with the title, abstract and key words of my scientific manuscript, respectively. Your task is analyzing my title, abstract and key words synthetically to find the most related, reputable journals for potential publication of my research based on an analysis of tens of millions of citation connections in database, such as Web of Science, Pubmed, Scopus, ScienceDirect and so on. You only need to provide me with the 15 most suitable journals. Your reply should include the name of journal, the cooresponding match score (The full score is ten). Respond in German. I want you to reply in text-based excel sheet and sort by matching scores in reverse order.\\nMy title is \\"XXX\\" My abstract is \\"XXX\\" My key words are \\"XXX\\".","description":"Ich m\xf6chte, dass Sie als Vermittler f\xfcr wissenschaftliche Manuskripte fungieren. Ich werde Ihnen den Titel, die Zusammenfassung und die Schl\xfcsselw\xf6rter meines wissenschaftlichen Manuskripts separat zur Verf\xfcgung stellen. Ihre Aufgabe ist es, meinen Titel, die Zusammenfassung und die Schl\xfcsselw\xf6rter zusammenzufassen, um die relevantesten und seri\xf6sesten Zeitschriften f\xfcr meine Forschung zu finden, basierend auf der Analyse von Millionen von Zitationslinks in Datenbanken wie Web of Science, Pubmed, Scopus, ScienceDirect usw. Alles, was Sie tun m\xfcssen, ist, mir die 15 am besten geeigneten Zeitschriften zu nennen. Ihre Antwort sollte den Namen der Zeitschrift und die entsprechende Trefferquote von 10 enthalten. Ich m\xf6chte, dass Sie in einer textbasierten Excel-Tabelle antworten, die in umgekehrter Reihenfolge nach der Trefferquote sortiert ist.","remark":"Beigetragen von @ScenerorSun, zitiert auf Seite B @Yams Potpourri."},"tags":["contribute","write"],"website":null,"count":1746,"related":[{"id":197,"title":"Natur Stil ber\xfchrt","remark":"Wird im Natur-Stil \xfcberarbeitet, oder kann einen Schreibstil liefern, den Sie nachahmen wollen. Beitrag von @Pfyuan77."},{"id":204,"title":"m\xfcndliches Skript","remark":"Verfassen von Videos, Live-Streams, Podcasts, Split-Screen und anderen gesprochenen Inhalten. Pitch von @bettycroco."},{"id":256,"title":"Artikel Generation Roboter","remark":"Ma\xdfgeschneiderte Produktion von Artikeln aus mehreren Perspektiven, mit guter Stabilit\xe4t. Gibt gelegentlich Regeln aus, die durch Anklicken von regenerate angepasst werden k\xf6nnen, und das Prompt-Wortformat bezieht sich auf Mr.-Ranedeer-AI-Tutor. Beitrag von @snowMan0622."}],"metaTitle":"Journal-Finder","metaDescription":"Welches Journal? Die besten seri\xf6sen Journale f\xfcr das Manuskript finden. 15 Empfehlungen. Jetzt testen.","faq":[{"q":"Existieren empfohlene Journals?","a":"Mainstream (Nature, Cell, PNAS) stimmt, Fachjournals werden teils erfunden oder sind veraltet, auch Impact Factor und Begutachtungszeiten. Pr\xfcfe die Liste in JCR oder Scimago und den aktuellen Einreichungsstatus auf der Journalseite."},{"q":"Ist der Impact Factor aktuell?","a":"Nein, er stammt aus Trainingsdaten und kann 1-2 Jahre alt sein. JCR aktualisiert jeden Juni; aktuelle IFs auf Web of Science. KI-Werte nur als Gr\xf6\xdfenordnung, nicht f\xfcr offizielle Berichte."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function s(){return(0,i.jsx)(r.A,{prompt:a,currentLanguage:"de"})}}}]);